    public void test_virtualFileCreation() throws Exception {
      initTestNodes();
      runWithinCommand(() -> {
        DummyFileSystem dummyFS = DummyFileSystem.getInstance();
        VirtualFile root = dummyFS.createRoot("");
        try {
          String expectedContent = "some content";
          VirtualFile file = TextComparison.createPath(dummyFS, root, "x/y", expectedContent);
          String content = VfsUtil.loadText(file);

          Assert.assertEquals(expectedContent, content);
          Assert.assertEquals("/x/y", file.getPath());
          Assert.assertEquals("/x", file.getParent().getPath());
          Assert.assertEquals(true, file.getParent().isDirectory());
          Assert.assertEquals(true, file.getParent().getParent().isDirectory());

          TestBody.this.createFileAndAssert("file with spaces.txt", "/file with spaces.txt");
          // quotes are disallowed on Windows
          if (!(SystemInfo.isWindows)) {
            TestBody.this.createFileAndAssert(" file.txt\"", "/ file.txt\"");
          }
          TestBody.this.createFileAndAssert("file.txt ", "/file.txt ");
          TestBody.this.createFileAndAssert("file. ", "/file. ");
          TestBody.this.createFileAndAssert(" file. ", "/ file. ");
          // €file.txt
          TestBody.this.createFileAndAssert("\u20ACfile.txt", "/\u20ACfile.txt");
          TestBody.this.createFileAndAssert("a/b/c/d/e/file.txt", "/a/b/c/d/e/file.txt");
          TestBody.this.createFileAndAssert("a//b///c/file.txt", "/a/b/c/file.txt");
          TestBody.this.createFileAndAssert("./file.txt", "/file.txt");
          // can't relativize because there is no reference path
          TestBody.this.createFileAndAssert("../file.txt", "/../file.txt");
          TestBody.this.createFileAndAssert("folder/../file.txt", "/file.txt");
          TestBody.this.createFileAndAssert("./folder/file.txt", "/folder/file.txt");
          // quotes are disallowed on Windows
          if (!(SystemInfo.isWindows)) {
            TestBody.this.createFileAndAssert("folder/\"", "/folder/\"");
          }
          TestBody.this.createFileAndAssert("folder//", "/folder");
          TestBody.this.createFileAndAssert("/dev/null", "/dev/null");
          TestBody.this.createFileAndAssert("/tmp/socket", "/tmp/socket");

          if (!(SystemInfo.isWindows)) {
            TestBody.this.createFileAndAssert("\\\\server\\share\\file.txt", "/server/share/file.txt");
          } else {
            // UNC paths are currently not supported and just stripped on Windows
            TestBody.this.createFileAndAssert("\\\\server\\share\\file.txt", "/file.txt");
          }

          // Standard Windows path with backslashes
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("C:\\Users\\test\\file.txt", "/Users/test/file.txt");
          } else {
            TestBody.this.createFileAndAssert("C:\\Users\\test\\file.txt", "/C:/Users/test/file.txt");
          }
          // Path with mixed slashes
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("C:/Users\\test\\file.txt", "/Users/test/file.txt");
          } else {
            TestBody.this.createFileAndAssert("C:/Users\\test\\file.txt", "/C:/Users/test/file.txt");
          }
          // UNC path (network share)
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("\\\\server\\share\\folder\\file.txt", "/folder/file.txt");
          } else {
            TestBody.this.createFileAndAssert("\\\\server\\share\\folder\\file.txt", "/server/share/folder/file.txt");
          }
          // Path with drive letter and trailing backslash
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("D:\\folder\\subfolder\\", "/folder/subfolder");
          } else {
            TestBody.this.createFileAndAssert("D:\\folder\\subfolder\\", "/D:/folder/subfolder");
          }
          // Path with spaces and special characters
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("C:\\Program Files\\Test Folder\\file.txt", "/Program Files/Test Folder/file.txt");
          } else {
            TestBody.this.createFileAndAssert("C:\\Program Files\\Test Folder\\file.txt", "/C:/Program Files/Test Folder/file.txt");
          }
          // Root of a drive; disallowed on Windows
          if (!(SystemInfo.isWindows)) {
            TestBody.this.createFileAndAssert("E:\\", "/E:");
          }
          // File at root of drive
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("F:\\file.txt", "/file.txt");
          } else {
            TestBody.this.createFileAndAssert("F:\\file.txt", "/F:/file.txt");
          }
          // Path with redundant backslashes
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("G:\\\\folder\\\\file.txt", "/folder/file.txt");
          } else {
            TestBody.this.createFileAndAssert("G:\\\\folder\\\\file.txt", "/G:/folder/file.txt");
          }
          // Path with dot and double dot navigation
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("C:\\folder\\.\\file.txt", "/folder/file.txt");
          } else {
            TestBody.this.createFileAndAssert("C:\\folder\\.\\file.txt", "/C:/folder/file.txt");
          }
          if (SystemInfo.isWindows) {
            TestBody.this.createFileAndAssert("C:\\folder\\..\\file.txt", "/file.txt");
          } else {
            TestBody.this.createFileAndAssert("C:\\folder\\..\\file.txt", "/C:/file.txt");
          }

        } catch (Exception e) {
          Assert.fail(e.getMessage());
        }
      });
    }

