    public void createFileAndAssert(String path, String expectedPath) {
      try {
        DummyFileSystem dummyFS = DummyFileSystem.getInstance();
        VirtualFile root = dummyFS.createRoot("");

        VirtualFile file = TextComparison.createPath(dummyFS, root, path, "some content");
        Assert.assertEquals(true, file.exists());
        Assert.assertEquals(expectedPath, file.getCanonicalPath());

      } catch (Exception e) {
        Assert.fail(e.toString());
      }
    }
